mapper.select:
select
    t.ent_code, t.out_put_id, t.template_code, t.template_name, t.show_attachment_flag,
    t.show_qualified_flag, t.prompt_text, t.item_array, t.remark, t.create_by, t.create_time, t.update_by, t.update_time,
    e.ent_name, o.out_put_code, o.out_put_name
from t_ops_template t
left join t_bas_enterprise e on e.ent_code = #{entCode}
left join t_ent_out_put_info o on o.out_put_id = #{outPutId}
where t.ent_code = '-1' and t.out_put_id = CONVERT(o.out_put_type, CHAR) and t.template_code = #{templateCode}

select t.ent_code, t.out_put_id, t.template_code, t.template_name, t.show_attachment_flag, t.show_qualified_flag, t.prompt_text, t.remark, t.create_by, t.create_time, t.update_by, t.update_time, e.ent_name, o.out_put_code, o.out_put_name from t_ops_template t left join t_bas_enterprise e on e.ent_code = t.ent_code left join t_ent_out_put_info o on o.out_put_id = t.out_put_id
and t.ent_code = '-1'
and t.ent_code = #{entCode}
and t.ent_code in
#{entCode}
and t.ent_code != '-1'
and t.out_put_id = #{outPutId}
and t.template_code = #{templateCode}
order by t.ent_code desc, t.out_put_id desc, t.template_code desc
